static void AddDynamicTree(const unsigned *ll_lengths,
                           const unsigned *d_lengths,
                           unsigned char *bp,
                           unsigned char **out, size_t *outsize)
/* AddDynamicTree calls EncodeTree nine times: eight size-only probe calls in the
